            <input 
              type="number" 
              required
              min="0"
              className="w-32 border border-slate-300 rounded p-2 text-lg font-bold bg-white text-slate-900"
              value={form.actualBoxCount}
              onChange={e => onUpdateBoxCount(parseInt(e.target.value) || 0)}
